<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> model_name</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
